def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 0, -1):
                for b in range(1, a + 4):
                    increment = ((ratio - a)**6) / (a * b * 0.8 + 1.2)
                    increment *= np.tanh(ratio * b / (a + 2)) * np.sin(ratio * (a + b) * 0.7)
                    priority += increment
            priority += (np.cosh(ratio - 7) * np.cos(ratio * 1.5)) ** 1.7 * 2
            if ratio > 10:
                for c in range(1, 6):
                    priority += np.exp(-0.3 * c * ratio) * np.sin(c * ratio) * 1.1
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 0.9) / (q + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log1p(ratio) * 14 - np.tanh(ratio - 5) * 3
            for d in range(3):
                priority += np.sin((i + d) * ratio * 0.9) * (0.5 + 0.2 * d)
        elif 2 <= ratio <= 5:
            sum_s = 0
            for r in range(1, 15):
                sum_s += ((ratio - 2) ** r) / (r * 2.0) * np.sin(r * ratio * 1.3)
            modulation = np.cos(9 * ratio) + np.sin(4 * ratio)
            priority = sum_s * modulation - np.log1p(ratio) * 9 + np.tanh(5 * (5 - ratio)) * 2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 14):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.1) * np.cos(n * ratio * 1.4)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.8) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for t in range(1, 20):
                s += ((1 - ratio) ** t) / (t * 3 + 1) * np.sin(t * ratio * 1.7)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 1.2) + 3)
            for u in range(1, 8):
                priority += ((1 - ratio) ** u) * np.cos(u * item * 1.3) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for v in range(1, 18):
                s += ((0.5 - ratio) ** v) / (v * 5 + 2) * np.cos(v * ratio * 2.3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.8) * 4
            for w in range(1, 9):
                priority += ((0.5 - ratio) ** w) / (w * 7) * np.cos(item * w * 1.2)
        else:
            s = 0
            for x in range(1, 14):
                s += ((0.2 - ratio) ** x) / (x * 6 + 3) * np.sin(x * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for y in range(1, 10):
                priority += ((0.2 - ratio) ** y) / (y * 8) * np.cos(item * y * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if i % 2 == 0:
            priority *= (1 + 0.05 * np.log1p(i + 1))
        else:
            priority /= (1 + 0.03 * np.sqrt(i + 2))
        primes = [2, 3, 5, 7, 11, 13, 17, 19, 23]
        if i in primes:
            priority += np.log1p(item + bin_cap) * 2
        priorities[i] = priority
    return priorities
